// Extract AI response text
const aiOutput = $input.first().json.output;

// Helper function to extract section content
function extractSection(text, sectionTitle) {
  const regex = new RegExp(`## ${sectionTitle}([\\s\\S]*?)(?=##|$)`, 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : 'Not available';
}

// Helper function to extract bullet points
function extractBullets(text) {
  const bullets = text.match(/[\*\+\-]\s+\*\*(.+?)\*\*/g) || [];
  return bullets.map(b => b.replace(/[\*\+\-]\s+\*\*(.+?)\*\*/, '$1')).join(', ');
}

// Helper function to clean markdown formatting
function cleanText(text) {
  return text
    .replace(/\*\*/g, '') // Remove bold markers
    .replace(/\*/g, '')   // Remove italic markers
    .replace(/\t/g, '')   // Remove tabs
    .replace(/\n\n+/g, '\n') // Remove multiple newlines
    .trim();
}

// Extract revenue figures
function extractRevenue(text) {
  const bestCase = text.match(/Best Case:\s*₹?([\d,]+)/i);
  const likelyCase = text.match(/Likely Case:\s*₹?([\d,]+)/i);
  const worstCase = text.match(/Worst Case:\s*₹?([\d,]+)/i);
  const weighted = text.match(/Weighted Pipeline Value:\s*₹?([\d,]+)/i);

  return {
    best_case: bestCase ? `₹${bestCase[1]}` : '₹0',
    likely_case: likelyCase ? `₹${likelyCase[1]}` : '₹0',
    worst_case: worstCase ? `₹${worstCase[1]}` : '₹0',
    weighted_value: weighted ? `₹${weighted[1]}` : '₹0'
  };
}

// Extract high-risk deals
function extractHighRiskDeals(text) {
  const dealName = text.match(/\*\*Deal Name:\*\*\s*(.+)/);
  const dealAmount = text.match(/\*\*Deal Amount:\*\*\s*₹?([\d,]+)/);
  const riskFactors = text.match(/\*\*Risk Factors:\*\*([\s\S]*?)(?=\*\*Recommended|$)/);

  let riskText = '';
  if (dealName && dealAmount) {
    riskText = `${dealName[1]} (₹${dealAmount[1]})`;
    if (riskFactors) {
      const factors = riskFactors[1].match(/\+\s+(.+)/g);
      if (factors) {
        riskText += ' - ' + factors.map(f => f.replace(/\+\s+/, '')).join('; ');
      }
    }
  }
  return riskText || 'No high-risk deals identified';
}

// Extract top recommendations
function extractRecommendations(text) {
  const recommendations = text.match(/\*\*Top 3 Actions.*?:\*\*([\s\S]*?)(?=\*\*Deals Requiring|$)/);
  if (recommendations) {
    const actions = recommendations[1].match(/\d+\.\s+\*\*(.+?)\*\*/g);
    if (actions) {
      return actions.map((a, i) => {
        const title = a.match(/\*\*(.+?)\*\*/)[1];
        const desc = recommendations[1].match(new RegExp(`${i + 1}\\.\\s+\\*\\*${title}\\*\\*:?\\s*(.+?)(?=\\n\\s*\\d+\\.|$)`, 's'));
        return `${i + 1}. ${title}${desc ? ': ' + cleanText(desc[1]) : ''}`;
      }).join('\n');
    }
  }
  return 'No specific recommendations';
}

// Extract revenue drivers
function extractRevenueDrivers(text) {
  const section = extractSection(aiOutput, 'Revenue Drivers Analysis');
  const keyDeals = section.match(/\*\*Key Deals:\*\*\s*(.+)/);
  const trends = section.match(/\*\*Revenue Trends:\*\*\s*(.+)/);

  let drivers = '';
  if (trends) drivers += cleanText(trends[1]) + '. ';
  if (keyDeals) drivers += 'Key deals: ' + cleanText(keyDeals[1]);

  return drivers || 'Insufficient data for analysis';
}

// Parse all sections
const revenue = extractRevenue(aiOutput);
const highRiskDeals = extractHighRiskDeals(extractSection(aiOutput, 'High-Risk Deals'));
const revenueDrivers = extractRevenueDrivers(aiOutput);
const recommendations = extractRecommendations(aiOutput);

// Format for Google Sheets
const formattedData = {
  timestamp: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
  forecast_period: new Date().toLocaleString('en-IN', { month: 'long', year: 'numeric' }),
  expected_revenue: revenue.likely_case,
  best_case: revenue.best_case,
  worst_case: revenue.worst_case,
  weighted_pipeline: revenue.weighted_value,
  high_risk_deals: highRiskDeals,
  revenue_drivers: revenueDrivers,
  recommendations: recommendations,
  full_ai_response: cleanText(aiOutput),
  report_sent_to: 'user@example.com, user@example.com'
};

// Format for Email HTML (clean sections)
const emailData = {
  timestamp: formattedData.timestamp,
  forecast_summary: `
    <p><strong>Expected Revenue:</strong> ${revenue.likely_case}</p>
    <p><strong>Best Case:</strong> ${revenue.best_case}</p>
    <p><strong>Worst Case:</strong> ${revenue.worst_case}</p>
    <p><strong>Weighted Pipeline:</strong> ${revenue.weighted_value}</p>
  `,
  high_risk_section: `
    <p>${highRiskDeals}</p>
  `,
  revenue_drivers_section: `
    <p>${revenueDrivers}</p>
  `,
  recommendations_section: `
    <pre style="background-color: #f4f4f4; padding: 15px; border-radius: 5px; white-space: pre-wrap;">${recommendations}</pre>
  `,
  full_report: aiOutput.replace(/\n/g, '<br>').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
};

// Return both formats
return [
  {
    json: {
      // For Google Sheets
      sheets_data: formattedData,

      // For Email
      email_data: emailData,

      // Raw data for debugging
      raw_output: aiOutput
    }
  }
];

// Helper: map region to currency
function getCurrency(region) {
  const map = {
    "India": "INR",
    "USA": "USD",
    "United States": "USD",
    "UK": "GBP",
    "United Kingdom": "GBP",
    "UAE": "AED"
  };
  return map[region] || "USD"; // default
}

return items.map(item => {
  const deal = item.json.properties || {};

  // Extract values safely
  const dealName = deal.dealname || "Unknown Deal";
  const dealAmount = Number(deal.amount || 0);

  const stage = deal.dealstage || "Unknown";
  const closeDate = deal.closedate
    ? new Date(Number(deal.closedate)).toISOString().split("T")[0]
    : null;

  const probability = deal.hs_probability
    ? Math.round(Number(deal.hs_probability) * 100)
    : 0;

  const owner = deal.hubspot_owner_id || "Unassigned";

  const region =
    deal.country ||
    deal.region ||
    deal.hs_country_region ||
    "Unknown";

  const currency = getCurrency(region);

  return {
    json: {
      "Deal Name": dealName,
      "Customer Name": deal.associatedcompanyname || "N/A",
      "Deal Amount": dealAmount,
      "Currency": currency,
      "Stage": stage,
      "Close Date": closeDate,
      "Probability (%)": probability,
      "Sales Owner": owner,
      "Region": region
    }
  };
});
